mapper.select:
select log_id, product_id, warehouse_id, area_id, location_id, shelf_id,
       bill_id, bill_no, bill_type, change_type, change_quantity,
       before_quantity, after_quantity, operator_id, create_time, remark
from wms_inventory_log

    and product_id = #{productId}
    and bill_id = #{billId}
    and change_type = #{changeType}

order by create_time desc
